// <auto-generated>
// Rust port of DBPersistAudit.core.cs.
//
// Audited strategy: insert assigns an identity and stamps audit columns;
// update soft-deletes the current row (is_active=0) and inserts a new version.
// Exposed as free functions because the dispatch lives in DBPersist.
// </auto-generated>

use common::{DatabaseProviderFactory, DomainObject};
use serde_json::Value;

use crate::db_connection::PersistError;
use crate::db_persist::{json_now, user_name, DBPersist};

pub fn insert<T: DomainObject>(obj: &mut T, connection_name: &str) -> Result<i64, PersistError> {
    let id = DBPersist::identity(obj.base(), connection_name)?;

    obj.base_mut().set("id", Value::from(id));
    obj.base_mut().set("txn_id", Value::from(id));
    obj.base_mut().set("is_active", Value::from(1));
    obj.base_mut().set("created_by", Value::String(user_name()));
    obj.base_mut().set("last_updated", json_now());
    obj.base_mut().set("last_updated_by", Value::String(user_name()));

    let table = obj.base().table_name.clone();
    let sql = DBPersist::insert_sql(obj, &table, connection_name);
    DBPersist::exec_cmd(&sql, connection_name)?;

    Ok(id)
}

pub fn update<T: DomainObject>(obj: &mut T, connection_name: &str) -> Result<(), PersistError> {
    let provider = DatabaseProviderFactory::create_provider(connection_name);
    let existing_id = obj.base().get("id").as_i64().unwrap_or_default();

    let deactivate_sql = format!(
        "UPDATE {} SET {} = 0 WHERE {} = {} AND {} = 1",
        provider.format_table_name(&obj.base().table_name),
        provider.format_column_name("is_active"),
        provider.format_column_name("id"),
        existing_id,
        provider.format_column_name("is_active"),
    );
    DBPersist::exec_cmd(&deactivate_sql, connection_name)?;

    // Deliberately does NOT force is_active=1 here (unlike insert, above) --
    // the new version row must carry whatever is_active the caller already
    // set on obj: Logic::update() sets it to 1 (a normal save keeps the
    // record active), Logic::delete() sets it to 0 (soft delete). Forcing it
    // to 1 unconditionally used to silently undo delete()'s is_active=0,
    // making the Edit page's Delete button appear to do nothing.
    let new_txn_id = DBPersist::identity(obj.base(), connection_name)?;
    obj.base_mut().set("txn_id", Value::from(new_txn_id));
    obj.base_mut().set("last_updated", json_now());
    obj.base_mut().set("last_updated_by", Value::String(user_name()));

    let table = obj.base().table_name.clone();
    let sql = DBPersist::insert_sql(obj, &table, connection_name);
    DBPersist::exec_cmd(&sql, connection_name)?;

    Ok(())
}
